files.content:
input {
    keyboard {
        xkb {
            layout "us"
        }
    }
    touchpad {
        tap
        natural-scroll
    }
}

// Noctalia is the desktop shell (bar, launcher, notifications, settings UI).
// The AUR noctalia-qs package provides the `qs` runtime.
spawn-at-startup "qs" "-c" "noctalia-shell"
spawn-at-startup "swaybg" "-c" "#1e1e2e"

prefer-no-csd

layout {
    gaps 16
    center-focused-column "never"
    default-column-width { proportion 0.5; }
    focus-ring {
        width 3
        active-color "{{accent}}"
        inactive-color "#45475a"
    }
}

screenshot-path "~/Pictures/Screenshots/Screenshot from %Y-%m-%d %H-%M-%S.png"

binds {
    // Apps
    Mod+Return hotkey-overlay-title="Open a terminal" { spawn "foot"; }
    Mod+D hotkey-overlay-title="Run an application" { spawn "fuzzel"; }
    Mod+Q { close-window; }

    // Focus (arrows or vim keys)
    Mod+Left  { focus-column-left; }
    Mod+Right { focus-column-right; }
    Mod+Up    { focus-window-up; }
    Mod+Down  { focus-window-down; }
    Mod+H     { focus-column-left; }
    Mod+L     { focus-column-right; }
    Mod+J     { focus-window-down; }
    Mod+K     { focus-window-up; }

    // Move windows / columns
    Mod+Shift+Left  { move-column-left; }
    Mod+Shift+Right { move-column-right; }
    Mod+Shift+Up    { move-window-up; }
    Mod+Shift+Down  { move-window-down; }

    // Workspaces
    Mod+1 { focus-workspace 1; }
    Mod+2 { focus-workspace 2; }
    Mod+3 { focus-workspace 3; }
    Mod+4 { focus-workspace 4; }
    Mod+Shift+1 { move-column-to-workspace 1; }
    Mod+Shift+2 { move-column-to-workspace 2; }
    Mod+Shift+3 { move-column-to-workspace 3; }
    Mod+Shift+4 { move-column-to-workspace 4; }

    // Window sizing / layout
    Mod+F { fullscreen-window; }
    Mod+M { maximize-column; }
    Mod+C { center-column; }
    Mod+R { switch-preset-column-width; }
    Mod+Minus { set-column-width "-10%"; }
    Mod+Equal { set-column-width "+10%"; }
    Mod+Comma { consume-window-into-column; }
    Mod+Period { expel-window-from-column; }

    // Screenshots
    Print { screenshot; }
    Mod+Print { screenshot-window; }

    // Volume & brightness keys
    XF86AudioRaiseVolume { spawn "wpctl" "set-volume" "@DEFAULT_AUDIO_SINK@" "5%+"; }
    XF86AudioLowerVolume { spawn "wpctl" "set-volume" "@DEFAULT_AUDIO_SINK@" "5%-"; }
    XF86AudioMute { spawn "wpctl" "set-mute" "@DEFAULT_AUDIO_SINK@" "toggle"; }
    XF86MonBrightnessUp { spawn "brightnessctl" "set" "+5%"; }
    XF86MonBrightnessDown { spawn "brightnessctl" "set" "5%-"; }

    // Session
    Mod+Shift+Slash { show-hotkey-overlay; }
    Mod+Escape { spawn "swaylock" "-f"; }
    Mod+Shift+E { quit; }
}
